import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { 
    Mail, 
    Phone, 
    MapPin, 
    Send, 
    User, 
    MessageSquare, 
    Clock, 
    CheckCircle,
    AlertCircle,
    Loader,
    Globe,
    Heart,
    Star,
    Sparkles
} from 'lucide-react';

const ContactSection = () => {
    const { t } = useTranslation();

    // Keep ALL your existing state and functionality exactly as is
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        subject: '',
        message: ''
    });

    const [status, setStatus] = useState({
        loading: false,
        success: false,
        error: false,
        message: ''
    });

    const [errors, setErrors] = useState({});

    // Keep ALL your existing form handling exactly as is
    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));

        // Clear error when user starts typing
        if (errors[name]) {
            setErrors(prev => ({
                ...prev,
                [name]: ''
            }));
        }
    };

    const validateForm = () => {
        const newErrors = {};

        if (!formData.name.trim()) {
            newErrors.name = t('contact.form.validation.nameRequired');
        }

        if (!formData.email.trim()) {
            newErrors.email = t('contact.form.validation.emailRequired');
        } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
            newErrors.email = t('contact.form.validation.emailInvalid');
        }

        if (!formData.subject.trim()) {
            newErrors.subject = t('contact.form.validation.subjectRequired');
        }

        if (!formData.message.trim()) {
            newErrors.message = t('contact.form.validation.messageRequired');
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!validateForm()) {
            return;
        }

        setStatus({ loading: true, success: false, error: false, message: '' });

        try {
            const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

            const response = await fetch(`${API_URL}/api/contact`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(formData),
            });

            if (!response.ok) {
                throw new Error('Network response was not ok');
            }

            const result = await response.json();

            setStatus({
                loading: false,
                success: true,
                error: false,
                message: t('contact.form.success')
            });

            // Reset form
            setFormData({
                name: '',
                email: '',
                subject: '',
                message: ''
            });

        } catch (error) {
            console.error('Contact form error:', error);
            setStatus({
                loading: false,
                success: false,
                error: true,
                message: t('contact.form.error')
            });
        }
    };

