                                    )}
                                </div>

                                {/* Submit Button */}
                                <div className="flex justify-end">
                                    <button
                                        type="submit"
                                        disabled={status.loading}
                                        className="flex items-center space-x-3 px-8 py-4 bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 disabled:from-gray-400 disabled:to-gray-500 text-white rounded-xl transition-all duration-300 hover:shadow-xl hover:-translate-y-1 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 disabled:cursor-not-allowed disabled:transform-none"
                                    >
                                        {status.loading ? (
                                            <>
                                                <Loader className="w-5 h-5 animate-spin" />
                                                <span className="font-medium">{t('contact.form.sending')}</span>
                                            </>
                                        ) : (
                                            <>
                                                <Send className="w-5 h-5" />
                                                <span className="font-medium">{t('contact.form.send')}</span>
                                            </>
                                        )}
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>
                </div>

                {/* Bottom CTA */}
                <div className="mt-16 text-center">
                    <div className="bg-white/80 backdrop-blur-xl rounded-3xl shadow-2xl border border-white/20 p-8 max-w-4xl mx-auto">
                        <div className="flex items-center justify-center space-x-3 mb-4">
                            <Heart className="w-8 h-8 text-red-500" />
                            <h3 className="text-2xl font-bold text-gray-800">{t('contact.cta.title')}</h3>
                        </div>
                        <p className="text-lg text-gray-600 mb-6 leading-relaxed">
                            {t('contact.cta.description')}
                        </p>
                        <div className="flex flex-col sm:flex-row gap-4 justify-center">
                            <a 
                                href="/apply" 
                                className="px-8 py-3 bg-gradient-to-r from-blue-500 to-purple-600 text-white rounded-xl hover:from-blue-600 hover:to-purple-700 transition-all duration-300 hover:shadow-xl hover:-translate-y-1 font-medium"
                            >
                                {t('contact.cta.buttons.apply')}
                            </a>
                            <a 
                                href="/courses" 
                                className="px-8 py-3 bg-white border-2 border-gray-200 text-gray-700 rounded-xl hover:bg-gray-50 hover:border-gray-300 transition-all duration-300 hover:shadow-lg hover:-translate-y-1 font-medium"
                            >
                                {t('contact.cta.buttons.courses')}
                            </a>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default ContactSection;
